import frappe
from frappe import _


def _is_impersonation_admin(user: str) -> bool:
    if user == 'Administrator':
        return True
    return 'System Manager' in frappe.get_roles(user)


@frappe.whitelist()
def login_as(target_user: str):
    current_user = frappe.session.user

    if current_user == 'Guest':
        frappe.throw(_('Login required'))

    if not _is_impersonation_admin(current_user):
        frappe.throw(_('Only System Managers can impersonate users'))

    target_user = (target_user or '').strip()
    if not target_user:
        frappe.throw(_('Target user is required'))

    if target_user == 'Administrator':
        frappe.throw(_('Impersonating Administrator is not allowed'))

    if not frappe.db.exists('User', target_user):
        frappe.throw(_('User {0} not found').format(target_user))

    enabled = frappe.db.get_value('User', target_user, 'enabled')
    if not enabled:
        frappe.throw(_('User {0} is disabled').format(target_user))

    frappe.logger('impersonation').info(
        'User %s impersonated %s', current_user, target_user
    )

    frappe.local.login_manager.login_as(target_user)
    return {'ok': True, 'target_user': target_user}
